// TypeScript implementation for Type Narrowing
interface TypeNarrowingPayload {
  id: number;
  title: string;
  status: 'active' | 'pending';
}

function processTypeNarrowing(item: TypeNarrowingPayload): string {
  return `[${item.id}] ${item.title}: ${item.status}`;
}

console.log(processTypeNarrowing({ id: 1, title: 'Type Narrowing', status: 'active' }));

